    input a,
    input b,
    input c,
    output carry,
    output sum
    );wire ci, si, ci2;

  wire temp1_a = a;
  wire temp2_b = b;
  assign ci = temp1_a & temp2_b;
    assign si = a ^ b;
    assign ci2 = si & c;
    assign sum = si ^ c;
    assign carry = ci | ci2;
